+    expect(result).toEqual({ status: "available" });
+    expect(fetchWithSsrFGuardMock).toHaveBeenCalledWith(
+      expect.objectContaining({
+        url: "http://127.0.0.1:8000/v1/models",
+        timeoutMs: 2500,
+      }),
+    );
+  });
